import React, { createContext, useContext, useState, useCallback } from 'react';
import Icon from '../components/Icon';
import closeIcon from '../assets/icons/inventory/close-icon.svg';

const UIContext = createContext();

export const UIProvider = ({ children }) => {
  const [toasts, setToasts] = useState([]);
  const [confirmConfig, setConfirmConfig] = useState(null);

  const showToast = useCallback((message, type = 'success') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);

    // Auto-remove after 4 seconds
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 4000);
  }, []);

  const removeToast = (id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  };

  const confirmAction = useCallback((title, message) => {
    return new Promise((resolve) => {
      setConfirmConfig({
        title,
        message,
        onConfirm: () => {
          setConfirmConfig(null);
          resolve(true);
        },
        onCancel: () => {
          setConfirmConfig(null);
          resolve(false);
        }
      });
    });
  }, []);

  return (
    <UIContext.Provider value={{ showToast, confirmAction }}>
      {children}
      
      {/* Toast Container */}
      <div className="toast-container">
        {toasts.map(toast => (
          <div key={toast.id} className={`toast toast-${toast.type}`}>
            <div className="toast-content">
              {toast.type === 'success' && <span className="toast-icon">✅</span>}
              {toast.type === 'error' && <span className="toast-icon">⚠️</span>}
              {toast.type === 'info' && <span className="toast-icon">ℹ️</span>}
              <p>{toast.message}</p>
            </div>
            <button onClick={() => removeToast(toast.id)} className="toast-close">
              &times;
            </button>
          </div>
        ))}
      </div>

      {/* Global Confirm Modal */}
      {confirmConfig && (
        <div className="modal-overlay" style={{ zIndex: 9999 }}>
          <div className="modal-content" style={{ maxWidth: '400px', animation: 'scaleUp 0.2s ease-out' }}>
            <div className="modal-header" style={{ padding: '20px', borderBottom: 'none' }}>
              <h2 style={{ fontSize: '20px', color: '#111827', margin: 0 }}>{confirmConfig.title}</h2>
              <button className="close-btn" onClick={confirmConfig.onCancel}>
                <Icon src={closeIcon} alt="Close" size={20} />
              </button>
            </div>
            <div style={{ padding: '0 20px 20px 20px' }}>
              <p style={{ color: '#4b5563', fontSize: '15px', margin: 0, lineHeight: '1.5' }}>
                {confirmConfig.message}
              </p>
            </div>
            <div className="modal-actions" style={{ padding: '16px 20px', background: '#f9fafb', margin: 0, borderTop: '1px solid #e5e7eb', borderRadius: '0 0 12px 12px' }}>
              <button className="btn-secondary" onClick={confirmConfig.onCancel}>
                Cancel
              </button>
              <button className="btn-primary" onClick={confirmConfig.onConfirm}>
                Confirm
              </button>
            </div>
          </div>
        </div>
      )}
    </UIContext.Provider>
  );
};

export const useUI = () => {
  const context = useContext(UIContext);
  if (!context) {
    throw new Error('useUI must be used within a UIProvider');
  }
  return context;
};
